exercises.solution_code:
#include <cassert>
#include <iostream>

int safeGet(const int* arr, int size, int idx)
{
    assert(idx >= 0 && "index must be non-negative");
    assert(idx < size && "index must be less than size");
    return arr[idx];
}

int main()
{
    int n;
    std::cin >> n;

    int arr[10]{};
    for (int i = 0; i < n; ++i)
        std::cin >> arr[i];

    int idx;
    std::cin >> idx;

    int value = safeGet(arr, n, idx);
    std::cout << "Element at index " << idx << ": " << value << '\n';

    return 0;
}

