exercises.solution_code:
#include <cassert>
#include <iostream>

constexpr int factorial(int n)
{
    int result = 1;
    for (int i = 2; i <= n; ++i)
        result *= i;
    return result;
}

static_assert(sizeof(int) >= 4, "This program requires at least 32-bit int");
static_assert(sizeof(long long) >= 8, "This program requires at least 64-bit long long");

int main()
{
    static_assert(factorial(12) == 479001600, "factorial(12) must fit in int");
    static_assert(factorial(0) == 1, "factorial(0) must be 1");

    int x;
    std::cin >> x;

    std::cout << "int size: " << sizeof(int) << '\n';
    std::cout << "max factorial(12) = " << factorial(12) << '\n';
    std::cout << "Runtime value: " << x << '\n';

    return 0;
}
